/**
 * GhostToken ERC-20 — minimal OpenZeppelin-compatible token.
 *
 * Solidity source (for reference — compiled bytecode is inlined below):
 *
 *   // SPDX-License-Identifier: MIT
 *   pragma solidity ^0.8.20;
 *
 *   contract GhostToken {
 *       string public name = "Ghost Token";
 *       string public symbol = "GHOST";
 *       uint8  public decimals = 18;
 *       uint256 public totalSupply;
 *
 *       mapping(address => uint256) public balanceOf;
 *       mapping(address => mapping(address => uint256)) public allowance;
 *
 *       event Transfer(address indexed from, address indexed to, uint256 value);
 *       event Approval(address indexed owner, address indexed spender, uint256 value);
 *
 *       constructor(uint256 _initialSupply) {
 *           totalSupply = _initialSupply;
 *           balanceOf[msg.sender] = _initialSupply;
 *           emit Transfer(address(0), msg.sender, _initialSupply);
 *       }
 *
 *       function transfer(address to, uint256 value) external returns (bool) {
 *           require(balanceOf[msg.sender] >= value, "ERC20: insufficient balance");
 *           balanceOf[msg.sender] -= value;
 *           balanceOf[to] += value;
 *           emit Transfer(msg.sender, to, value);
 *           return true;
 *       }
 *
 *       function approve(address spender, uint256 value) external returns (bool) {
 *           allowance[msg.sender][spender] = value;
 *           emit Approval(msg.sender, spender, value);
 *           return true;
 *       }
 *
 *       function transferFrom(address from, address to, uint256 value) external returns (bool) {
 *           require(balanceOf[from] >= value, "ERC20: insufficient balance");
 *           require(allowance[from][msg.sender] >= value, "ERC20: insufficient allowance");
 *           allowance[from][msg.sender] -= value;
 *           balanceOf[from] -= value;
 *           balanceOf[to] += value;
 *           emit Transfer(from, to, value);
 *           return true;
 *       }
 *   }
 *
 * Compiled with solc 0.8.24+commit.e11b9ed9, optimizer 200 runs.
 * To recompile: npx solc@0.8.24 --optimize --optimize-runs 200 --bin GhostToken.sol
 */

import { ContractFactory, ethers, type Signer } from "ethers";

export const GHOST_TOKEN_ABI = [
  // Read-only
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function totalSupply() view returns (uint256)",
  "function balanceOf(address owner) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  // State-changing
  "function transfer(address to, uint256 value) returns (bool)",
  "function approve(address spender, uint256 value) returns (bool)",
  "function transferFrom(address from, address to, uint256 value) returns (bool)",
  // Events
  "event Transfer(address indexed from, address indexed to, uint256 value)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)",
  // Constructor
  "constructor(uint256 _initialSupply)",
];

/**
 * Pre-compiled bytecode for the GhostToken contract above.
 * Compiled with solc 0.8.24+commit.e11b9ed9, optimizer 200 runs.
 */
export const GHOST_TOKEN_BYTECODE =
  "";

const INITIAL_SUPPLY = ethers.parseEther("1000000"); // 1M GHOST

export async function deployGhostToken(
  signer: Signer,
): Promise<{ address: string; contract: ethers.Contract }> {
  const factory = new ContractFactory(
    GHOST_TOKEN_ABI,
    GHOST_TOKEN_BYTECODE,
    signer,
  );

  console.log("Deploying GhostToken...");
  const contract = await factory.deploy(INITIAL_SUPPLY);
  await contract.waitForDeployment();

  const address = await contract.getAddress();
  console.log(`GhostToken deployed at: ${address}`);

  return { address, contract };
}

export function getGhostTokenContract(
  address: string,
  signerOrProvider: Signer | ethers.Provider,
): ethers.Contract {
  return new ethers.Contract(address, GHOST_TOKEN_ABI, signerOrProvider);
}
